#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K, M;
        scanf("%d %d %d", &N, &K, &M);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        int L[M], R[M], C[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &L[i], &R[i], &C[i]);
        }
        int dp[N + 1][K + 1];
        for (int i = 0; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = 0;
            }
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 0; j <= K; j++) {
                dp[i][j] = dp[i - 1][j];
                if (A[i - 1] > 0) {
                    dp[i][j] += A[i - 1];
                }
                for (int k = 0; k < M; k++) {
                    if (L[k] <= i && i <= R[k] && j >= C[k]) {
                        dp[i][j] = (dp[i][j] > dp[i - 1][j - C[k]] + A[i - 1]) ? dp[i][j] : dp[i - 1][j - C[k]] + A[i - 1];
                    }
                }
            }
        }
        int max = 0;
        for (int i = 0; i <= K; i++) {
            if (dp[N][i] > max) {
                max = dp[N][i];
            }
        }
        printf("%d\n", max);
    }
    return 0;
}

