    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            int M = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int[] L = new int[M];
            int[] R = new int[M];
            int[] C = new int[M];
            for (int i = 0; i < M; i++) {
                L[i] = sc.nextInt();
                R[i] = sc.nextInt();
                C[i] = sc.nextInt();
            }
            int[][] dp = new int[N + 1][K + 1];
            for (int i = 1; i <= N; i++) {
                for (int j = 0; j <= K; j++) {
                    dp[i][j] = dp[i - 1][j];
                    if (A[i - 1] > 0) {
                        dp[i][j] += A[i - 1];
                    }
                    for (int k = 0; k < M; k++) {
                        if (L[k] <= i && i <= R[k] && j >= C[k]) {
                            dp[i][j] = Math.max(dp[i][j], dp[i - 1][j - C[k]] + A[i - 1]);
                        }
                    }
                }
            }
            int max = 0;
            for (int i = 0; i <= K; i++) {
                if (dp[N][i] > max) {
                    max = dp[N][i];
                }
            }
            System.out.println(max);
